        [TestMethod]
        public void MsgPackBinaryString1()
        {
            var output = Algorand.Utils.Encoder.DecodeFromMsgPack<string>(HexToBytes("d920000000000000000000000000000000000000000000000000002112687f3e2b01"));
            Assert.AreEqual("0x000000000000000000000000000000000000000000000000002112687f3e2b01", output);
        }
        [TestMethod]
        public void MsgPackBinaryString2()
        {
            var input = HexToBytes("d920000000000000000000000000000000000000000000000000000008a677166d10");
            var options = MessagePack.MessagePackSerializerOptions.Standard.WithResolver(
                MessagePack.Resolvers.CompositeResolver.Create(
                    new MessagePack.Formatters.IMessagePackFormatter[] { Algorand.Algod.Model.Converters.MsgPack.NullableStringFormatterMsgPack.Instance },
                    new MessagePack.IFormatterResolver[] { MessagePack.Resolvers.ContractlessStandardResolver.Instance }
                )
            );
            var output = MessagePack.MessagePackSerializer.Deserialize<string>(input, options);
            Assert.AreEqual("0x000000000000000000000000000000000000000000000000000008a677166d10", output);
        }
        [TestMethod]
        public void MsgPackPlainString()
        {
            var input = HexToBytes("d92068656C6C6F20616C676F72616E642068656C6C6F20616C676F72616E64206865");
            var options = MessagePack.MessagePackSerializerOptions.Standard.WithResolver(
                MessagePack.Resolvers.CompositeResolver.Create(
                    new MessagePack.Formatters.IMessagePackFormatter[] { Algorand.Algod.Model.Converters.MsgPack.NullableStringFormatterMsgPack.Instance },
                    new MessagePack.IFormatterResolver[] { MessagePack.Resolvers.ContractlessStandardResolver.Instance }
                )
            );
            var output = MessagePack.MessagePackSerializer.Deserialize<string>(input, options);
            Assert.AreEqual("hello algorand hello algorand he", output);
        }

        [TestMethod]
        public void FirstBlockTest()
        {
            var input = HexToBytes("");
            var output = Algorand.Utils.Encoder.DecodeFromMsgPack<CertifiedBlock>(input);
            Assert.IsNotNull(output);
            Assert.IsNotNull(output.Block);
            Assert.IsNull(output.Block.PreviousBlockHash);
            Assert.IsNotNull(output.Cert);
            Assert.IsNull(output.Cert.Votes);
            Assert.AreEqual("mainnet-v1.0", output.Block.GenesisId);
            Assert.IsNull(output.Block.Transactions);
            Assert.AreEqual("C061C4D8FC1DBDDED2D7604BE4568E3F6D041987AC37BDE4B620B5AB39248ADF", Convert.ToHexString(output.Block.Seed));

        }
        [TestMethod]
        public void SecondBlockTest()
        {
            var input = HexToBytes("");
            var output = Algorand.Utils.Encoder.DecodeFromMsgPack<CertifiedBlock>(input);
            Assert.IsNotNull(output);
            Assert.IsNotNull(output.Block);
            Assert.IsNotNull(output.Block.PreviousBlockHash);
            Assert.AreEqual(1ul, output.Block.Round);
            Assert.AreEqual("mainnet-v1.0", output.Block.GenesisId);
            Assert.IsNull(output.Block.Transactions);
            Assert.AreEqual("727388D846BC9F5A7BF97A92F67205C49CB6992263D74ABBF4DA60C4D58197DC", Convert.ToHexString(output.Block.Seed));
            Assert.AreEqual("C272EC8DCF04C9E7FCD929E6D3C2206879168E8D87C90AD5F2AA7AAFCFAE4DE7", Convert.ToHexString(output.Block.PreviousBlockHash));


            Assert.IsNotNull(output.Cert);
            Assert.IsNotNull(output.Cert.Votes);
            Assert.AreEqual(20, output.Cert.Votes.Count);

        }
        [TestMethod]
        public void DecodeVoteTest()
        {
            var input = HexToBytes("");
            var output = Algorand.Utils.Encoder.DecodeFromMsgPack<Algorand.Algod.Model.Agreement.Vote>(input);
            Assert.IsNotNull(output);
            Assert.IsNotNull(output.R);
            Assert.IsNotNull(output.Cred);
            Assert.IsNotNull(output.Sig);
            Assert.AreEqual("JEMT52UDGZYH4TWODGLN6SSH3O5CLU22KPLENGVBZINNUBYNEJTI4EBWG4", output.R.Sender.EncodeAsString());

        }

